import{_ as t,o,c as n,O as a}from"./chunks/framework.E_ICI9Fe.js";const m=JSON.parse('{"title":"CSS Anchor Positioning: The End of JavaScript Tooltips","description":"Tether any element to another purely in CSS — no getBoundingClientRect, no scroll listeners. Tooltips, dropdowns, and popovers that flip automatically when they overflow the viewport.","frontmatter":{"layout":"article","title":"CSS Anchor Positioning: The End of JavaScript Tooltips","description":"Tether any element to another purely in CSS — no getBoundingClientRect, no scroll listeners. Tooltips, dropdowns, and popovers that flip automatically when they overflow the viewport.","photo":"https://fastly.picsum.photos/id/47/200/300.jpg?hmac=qgEtmhYzb3otRNnLN3afPLzmn6VJKj6x86OGOjDcBxQ","original_url":"https://developer.chrome.com/blog/anchor-positioning-api","source_name":"Chrome Developers","source_author":"Una Kravets","tags":["css","layout"],"significance":3,"head":[["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"CSS Anchor Positioning: The End of JavaScript Tooltips"}],["meta",{"property":"og:description","content":"Tether any element to another purely in CSS — no getBoundingClientRect, no scroll listeners. Tooltips, dropdowns, and popovers that flip automatically when they overflow the viewport."}],["meta",{"property":"og:url","content":"https://.frsource.org/articles/2026-03-06/css-anchor-positioning"}],["meta",{"property":"og:site_name","content":"digestweb.dev"}],["meta",{"property":"og:image","content":"https://fastly.picsum.photos/id/47/200/300.jpg?hmac=qgEtmhYzb3otRNnLN3afPLzmn6VJKj6x86OGOjDcBxQ"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"CSS Anchor Positioning: The End of JavaScript Tooltips"}],["meta",{"name":"twitter:description","content":"Tether any element to another purely in CSS — no getBoundingClientRect, no scroll listeners. Tooltips, dropdowns, and popovers that flip automatically when they overflow the viewport."}],["meta",{"name":"twitter:image","content":"https://fastly.picsum.photos/id/47/200/300.jpg?hmac=qgEtmhYzb3otRNnLN3afPLzmn6VJKj6x86OGOjDcBxQ"}]]},"headers":[],"relativePath":"articles/2026-03-06/css-anchor-positioning.md","filePath":"articles/2026-03-06/css-anchor-positioning.md"}'),i={name:"articles/2026-03-06/css-anchor-positioning.md"};function r(s,e,l,c,p,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h2 id="summary-key-takeaways" tabindex="-1">Summary &amp; Key Takeaways <a class="header-anchor" href="#summary-key-takeaways" aria-label="Permalink to “Summary &amp; Key Takeaways”">​</a></h2><p>CSS Anchor Positioning is finally shipping in all major browsers — and it fundamentally changes how we build tooltips, dropdowns, and floating UI.</p><p>The new <code>anchor()</code> function lets you tether any element to a named anchor purely in CSS. No <code>getBoundingClientRect</code>, no scroll listeners, no JavaScript positioning loops. The browser handles collision detection automatically via <code>@position-try</code> fallback blocks, flipping your popover when it would overflow the viewport.</p><ul><li><strong><code>anchor-name: --btn</code></strong> — declare any element as an anchor</li><li><strong><code>position-anchor: --btn</code></strong> — bind a floating element to it</li><li><strong><code>@position-try</code></strong> — define fallback positions for auto-flipping</li><li><strong><code>position-area</code></strong> — place the element relative to the anchor with a simple grid-like syntax</li></ul><h2 id="our-commentary" tabindex="-1">Our Commentary <a class="header-anchor" href="#our-commentary" aria-label="Permalink to “Our Commentary”">​</a></h2><p>Combined with the new <code>position-area</code> property, complex overlay layouts that once required hundreds of lines of JS can be expressed in a handful of CSS rules. This is one of the most impactful additions to the platform in years — and it pairs beautifully with the Popover API for fully declarative floating UI.</p>',6)])])}const y=t(i,[["render",r]]);export{m as __pageData,y as default};
